sql:
SELECT sport_name
FROM sports
ORDER BY sport_name ASC;

SELECT COUNT(*) 
FROM sports 
WHERE category = 'team sports';

SELECT sport_name, description, governing_body
FROM sports
WHERE category = 'team sports';

external_knowledge:
- 'current sports' refers to the sports with active seasons;
- 'ongoing seasons' are seasons with the status marked as 'active';
- 'victories tallied' corresponds to the sum of wins in each season for the given sport.

- "ancient giants" metaphorically refers to the teams founded before 1900;
- "planted their roots in time immemorial before the dawn of the twentieth century" refers to teams founded before the year 1900;
- "vast arenas" and "temples of sport" metaphorically refer to stadiums with capacities greater than 100,000;
- "roaring crowds of over a hundred thousand" refers to stadium capacities over 100,000;
- "from the most cavernous to the smallest" means sorting by stadium capacity in descending order.
